// app/page.tsx
import { Suspense } from 'react';
import { getAllProducts, syncLatestCatalog } from '@/lib/db';

function formatPrice(price: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD'
  }).format(price);
}

async function ProductsTable() {
  const products = await getAllProducts();

  return (
    <div style={{ marginTop: 32, overflowX: 'auto' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ textAlign: 'left', borderBottom: '1px solid #e5e7eb' }}>
            <th style={{ padding: '12px 8px' }}>ID</th>
            <th style={{ padding: '12px 8px' }}>Name</th>
            <th style={{ padding: '12px 8px' }}>Price</th>
            <th style={{ padding: '12px 8px' }}>Inventory</th>
            <th style={{ padding: '12px 8px' }}>Availability</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
              <td style={{ padding: '12px 8px' }}>{product.id}</td>
              <td style={{ padding: '12px 8px', fontWeight: 600 }}>{product.name}</td>
              <td style={{ padding: '12px 8px' }}>{formatPrice(product.price)}</td>
              <td style={{ padding: '12px 8px' }}>{product.inventory}</td>
              <td style={{ padding: '12px 8px' }}>{product.availability}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default function Page() {
  async function handleSync() {
    'use server';
    await syncLatestCatalog();
  }

  return (
    <main style={{ padding: 32, fontFamily: 'Arial, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 24, flexWrap: 'wrap' }}>
        <div>
          <h1 style={{ margin: 0 }}>Product Catalog</h1>
          <p style={{ margin: '8px 0 0', color: '#555' }}>
            Cached catalog data with background sync for fast day-to-day browsing.
          </p>
        </div>

        <form action={handleSync}>
          <button
            type="submit"
            style={{
              background: '#111827',
              color: 'white',
              border: 'none',
              borderRadius: 8,
              padding: '12px 16px',
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <Suspense fallback={<p style={{ marginTop: 32 }}>Loading catalog…</p>}>
        <ProductsTable />
      </Suspense>
    </main>
  );
}


