import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

async function syncLatestCatalog() {
  'use server';

  revalidateTag('products', 'max');
}

export default async function Page() {
  const products = await getAllProducts();
  const updatedAt = new Date().toLocaleString('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short'
  });

  return (
    <main style={styles.page}>
      <section style={styles.shell}>
        <header style={styles.header}>
          <div>
            <p style={styles.kicker}>Admin catalog</p>
            <h1 style={styles.title}>Product Catalog</h1>
            <p style={styles.description}>
              Browse cached catalog data quickly. Trigger a sync when ERP/PIM data changes, then keep
              working while fresh data propagates across catalog views.
            </p>
          </div>

          <form action={syncLatestCatalog}>
            <button type="submit" style={styles.button}>
              Sync latest catalog
            </button>
          </form>
        </header>

        <div style={styles.metaRow}>
          <span>Last rendered: {updatedAt}</span>
          <span>Cache tag: products</span>
        </div>

        <section style={styles.grid} aria-label="Product catalog">
          {products.map(product => (
            <article key={product.id} style={styles.card}>
              <div style={styles.cardTop}>
                <h2 style={styles.cardTitle}>{product.name}</h2>
                <span style={styles.badge}>{product.availability}</span>
              </div>
              <dl style={styles.details}>
                <div>
                  <dt style={styles.term}>Price</dt>
                  <dd style={styles.value}>${product.price}</dd>
                </div>
                <div>
                  <dt style={styles.term}>Inventory</dt>
                  <dd style={styles.value}>{product.stock} units</dd>
                </div>
              </dl>
            </article>
          ))}
        </section>
      </section>
    </main>
  );
}

